changeSet.sql:
-- CUSTOMERS INSERT INTO permissions (id, code, name, group_name, description) VALUES (uuid_generate_v4(), 'CUSTOMER_VIEW', 'Просмотр клиентов', 'CUSTOMERS', 'Просматривать список и карточки клиентов'), (uuid_generate_v4(), 'CUSTOMER_CREATE', 'Создание клиентов', 'CUSTOMERS', 'Создавать новых клиентов'), (uuid_generate_v4(), 'CUSTOMER_EDIT', 'Редактирование клиентов', 'CUSTOMERS', 'Изменять данные клиентов'), (uuid_generate_v4(), 'CUSTOMER_DELETE', 'Удаление клиентов', 'CUSTOMERS', 'Удалять клиентов из системы');
-- TASKS INSERT INTO permissions (id, code, name, group_name, description) VALUES (uuid_generate_v4(), 'TASK_VIEW', 'Просмотр задач', 'TASKS', 'Просматривать задачи'), (uuid_generate_v4(), 'TASK_CREATE', 'Создание задач', 'TASKS', 'Создавать новые задачи'), (uuid_generate_v4(), 'TASK_EDIT', 'Редактирование задач', 'TASKS', 'Изменять задачи'), (uuid_generate_v4(), 'TASK_DELETE', 'Удаление задач', 'TASKS', 'Удалять задачи'), (uuid_generate_v4(), 'TASK_ASSIGN', 'Назначение задач', 'TASKS', 'Назначать задачи другим пользователям');
-- ORDERS INSERT INTO permissions (id, code, name, group_name, description) VALUES (uuid_generate_v4(), 'ORDER_VIEW', 'Просмотр заказов', 'ORDERS', 'Просматривать заказы'), (uuid_generate_v4(), 'ORDER_CREATE', 'Создание заказов', 'ORDERS', 'Создавать новые заказы'), (uuid_generate_v4(), 'ORDER_EDIT', 'Редактирование заказов', 'ORDERS', 'Изменять заказы и статусы'), (uuid_generate_v4(), 'ORDER_DELETE', 'Удаление заказов', 'ORDERS', 'Удалять заказы');
-- PRODUCTS INSERT INTO permissions (id, code, name, group_name, description) VALUES (uuid_generate_v4(), 'PRODUCT_VIEW', 'Просмотр товаров', 'PRODUCTS', 'Просматривать каталог товаров'), (uuid_generate_v4(), 'PRODUCT_MANAGE', 'Управление товарами', 'PRODUCTS', 'Создавать, редактировать и удалять товары');
-- ADMIN INSERT INTO permissions (id, code, name, group_name, description) VALUES (uuid_generate_v4(), 'USER_VIEW', 'Просмотр пользователей', 'ADMIN', 'Просматривать список пользователей'), (uuid_generate_v4(), 'USER_MANAGE', 'Управление пользователями', 'ADMIN', 'Приглашать, редактировать, деактивировать пользователей'), (uuid_generate_v4(), 'ROLE_VIEW', 'Просмотр ролей', 'ADMIN', 'Просматривать роли и права'), (uuid_generate_v4(), 'ROLE_MANAGE', 'Управление ролями', 'ADMIN', 'Создавать и редактировать роли, назначать права'), (uuid_generate_v4(), 'TENANT_MANAGE', 'Настройки тенанта', 'ADMIN', 'Управлять настройками организации и модулями');

-- ADMIN — все права INSERT INTO role_permissions (role_id, permission_id) SELECT '00000000-0000-0000-0000-000000000001', id FROM permissions;
-- MANAGER — всё кроме управления ролями и тенантом INSERT INTO role_permissions (role_id, permission_id) SELECT '00000000-0000-0000-0000-000000000002', id FROM permissions WHERE code NOT IN ('ROLE_MANAGE', 'TENANT_MANAGE', 'USER_MANAGE');
-- SALES — клиенты, заказы, товары (только просмотр товаров) INSERT INTO role_permissions (role_id, permission_id) SELECT '00000000-0000-0000-0000-000000000003', id FROM permissions WHERE code IN ( 'CUSTOMER_VIEW','CUSTOMER_CREATE','CUSTOMER_EDIT', 'ORDER_VIEW','ORDER_CREATE','ORDER_EDIT', 'PRODUCT_VIEW', 'TASK_VIEW','TASK_CREATE','TASK_EDIT' );
-- OBSERVER — только просмотр INSERT INTO role_permissions (role_id, permission_id) SELECT '00000000-0000-0000-0000-000000000004', id FROM permissions WHERE code IN ( 'CUSTOMER_VIEW','TASK_VIEW','ORDER_VIEW','PRODUCT_VIEW','USER_VIEW','ROLE_VIEW' );
